+/**
+ * Simple in-process event bus with publish/subscribe pattern.
+ *
+ * Used for decoupled communication between notification channels.
+ * Each subscriber receives a copy of the published event data.
+ */
+
+export type EventHandler<T = unknown> = (data: T) => void | Promise<void>;
+
+export class NotificationEventBus<TEventMap extends Record<string, unknown> = Record<string, unknown>> {
+  private subscribers = new Map<string, EventHandler[]>();
+
+  /**
+   * Subscribe to an event type. Returns an unsubscribe function.
+   */
+  subscribe<K extends string & keyof TEventMap>(
+    event: K,
+    handler: EventHandler<TEventMap[K]>,
+  ): () => void {
+    const handlers = this.subscribers.get(event) ?? [];
+    handlers.push(handler as EventHandler);
+    this.subscribers.set(event, handlers);
+
+    return () => {
+      const current = this.subscribers.get(event) ?? [];
+      const index = current.indexOf(handler as EventHandler);
+      if (index >= 0) {
+        current.splice(index, 1);
+      }
+    };
+  }
+
+  /**
+   * Publish an event to all subscribers of that event type.
+   */
+  async publish<K extends string & keyof TEventMap>(
+    event: K,
+    data: TEventMap[K],
+  ): Promise<void> {
+    const handlers = this.subscribers.get(event) ?? [];
+    for (const handler of handlers) {
+      await handler(data);
+    }
+  }
+
+  /**
+   * Clear all subscribers.
+   */
+  clear(): void {
+    this.subscribers.clear();
+  }
+}

