/**
 * Simple in-process event bus with publish/subscribe pattern.
 *
 * Used for decoupled communication between notification channels.
 * Each subscriber receives a copy of the published event data.
 */

export type EventHandler<T = unknown> = (data: T) => void | Promise<void>;

export class NotificationEventBus<TEventMap extends Record<string, unknown> = Record<string, unknown>> {
  private subscribers = new Map<string, EventHandler[]>();

  /**
   * Subscribe to an event type. Returns an unsubscribe function.
   */
  subscribe<K extends string & keyof TEventMap>(
    event: K,
    handler: EventHandler<TEventMap[K]>,
  ): () => void {
    const handlers = this.subscribers.get(event) ?? [];
    handlers.push(handler as EventHandler);
    this.subscribers.set(event, handlers);

    return () => {
      const current = this.subscribers.get(event) ?? [];
      const index = current.indexOf(handler as EventHandler);
      if (index >= 0) {
        current.splice(index, 1);
      }
    };
  }

  /**
   * Publish an event to all subscribers of that event type.
   */
  async publish<K extends string & keyof TEventMap>(
    event: K,
    data: TEventMap[K],
  ): Promise<void> {
    const handlers = this.subscribers.get(event) ?? [];
    for (const handler of handlers) {
      await handler(data);
    }
  }

  /**
   * Clear all subscribers.
   */
  clear(): void {
    this.subscribers.clear();
  }
}

/**
 * Notification service — handles sending notifications in response to events.
 *
 * Uses an EventBus (publish/subscribe) pattern for dispatching notifications
 * to channel handlers. The service listens to application events (e.g.,
 * order:created) and publishes NotificationEvents to a notification-specific
 * event bus. Channel handlers (e.g., EmailChannelHandler) subscribe to those
 * events and process them independently.
 *
 * This design is extensible — additional channels (SMS, push, etc.) can be
 * added by creating new handlers that subscribe to the notification event bus.
 *
 * Depends on:
 * - EventBus (application event system) for receiving domain events
 * - NotificationEventBus (notification dispatch) for routing to channels
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import { statusChangeCallbacks } from '../utils/callback-registry.js';
import { NotificationEventBus } from '../utils/event-bus.js';
import { Logger } from '../utils/logger.js';

export interface NotificationEvent {
  type: 'email';
  recipient: string;
  subject: string;
  body: string;
}

export interface NotificationEventMap {
  'notification:send': NotificationEvent;
}

export interface Notification {
  id: string;
  type: string;
  recipient: string;
  subject: string;
  body: string;
  sentAt: Date;
}

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

/**
 * Email channel handler — subscribes to the notification event bus
 * and stores email notifications.
 */
export class EmailChannelHandler {
  private logger = new Logger('EmailChannelHandler');
  private sent: Notification[] = [];

  constructor(private notificationBus: NotificationEventBus<NotificationEventMap>) {
    this.notificationBus.subscribe('notification:send', (event) => {
      if (event.type === 'email') {
        this.handleEmail(event);
      }
    });
  }

  private handleEmail(event: NotificationEvent): void {
    const notification: Notification = {
      id: generateNotificationId(),
      type: 'email',
      recipient: event.recipient,
      subject: event.subject,
      body: event.body,
      sentAt: new Date(),
    };
    this.sent.push(notification);
    this.logger.info(`Email sent: ${notification.id} to ${event.recipient}`);
  }

  getSentEmails(): Notification[] {
    return [...this.sent];
  }

  getSentCount(): number {
    return this.sent.length;
  }

  clearSent(): void {
    this.sent = [];
  }
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private notificationBus: NotificationEventBus<NotificationEventMap>;

  constructor(
    private eventBus: EventBus,
    notificationBus?: NotificationEventBus<NotificationEventMap>,
  ) {
    this.notificationBus = notificationBus ?? new NotificationEventBus<NotificationEventMap>();
    this.registerHandlers();
    this.subscribeToNotificationBus();
  }

  getNotificationBus(): NotificationEventBus<NotificationEventMap> {
    return this.notificationBus;
  }

  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    statusChangeCallbacks.register((event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Subscribe to the notification bus to maintain the internal notifications list.
   */
  private subscribeToNotificationBus(): void {
    this.notificationBus.subscribe('notification:send', (event) => {
      const notification: Notification = {
        id: generateNotificationId(),
        type: event.type,
        recipient: event.recipient,
        subject: event.subject,
        body: event.body,
        sentAt: new Date(),
      };
      this.notifications.push(notification);
      this.logger.info(`Notification recorded: ${notification.id} to ${event.recipient}`);
    });
  }

  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    this.publishNotification({
      type: 'email',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
    });
  }

  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    this.publishNotification({
      type: 'email',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
    });
  }

  private publishNotification(event: NotificationEvent): void {
    void this.notificationBus.publish('notification:send', event);
  }

  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  getNotificationCount(): number {
    return this.notifications.length;
  }

  clearNotifications(): void {
    this.notifications = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
