describe('NotificationEventBus', () => {
  let bus: NotificationEventBus<NotificationEventMap>;

  beforeEach(() => {
    bus = new NotificationEventBus<NotificationEventMap>();
  });

  it('should deliver events to subscribers', async () => {
    const received: string[] = [];
    bus.subscribe('notification:send', (event) => {
      received.push(event.recipient);
    });

    await bus.publish('notification:send', {
      type: 'email',
      recipient: 'test@example.com',
      subject: 'Test',
      body: 'Test',
    });

    expect(received).toEqual(['test@example.com']);
  });

  it('should support unsubscribe', async () => {
    const received: string[] = [];
    const unsubscribe = bus.subscribe('notification:send', (event) => {
      received.push(event.recipient);
    });

    await bus.publish('notification:send', {
      type: 'email',
      recipient: 'first@example.com',
      subject: 'Test',
      body: 'Test',
    });

    unsubscribe();

    await bus.publish('notification:send', {
      type: 'email',
      recipient: 'second@example.com',
      subject: 'Test',
      body: 'Test',
    });

    expect(received).toEqual(['first@example.com']);
  });

  it('should support multiple subscribers', async () => {
    const sub1: string[] = [];
    const sub2: string[] = [];

    bus.subscribe('notification:send', (event) => { sub1.push(event.recipient); });
    bus.subscribe('notification:send', (event) => { sub2.push(event.recipient); });

    await bus.publish('notification:send', {
      type: 'email',
      recipient: 'test@example.com',
      subject: 'Test',
      body: 'Test',
    });

    expect(sub1).toEqual(['test@example.com']);
    expect(sub2).toEqual(['test@example.com']);
  });

  it('should clear all subscribers', async () => {
    const received: string[] = [];
    bus.subscribe('notification:send', (event) => { received.push(event.recipient); });

    bus.clear();

    await bus.publish('notification:send', {
      type: 'email',
      recipient: 'test@example.com',
      subject: 'Test',
      body: 'Test',
    });

    expect(received).toEqual([]);
  });
});
